        if (!origContent) return;

        const tag = origContent.tagName.toLowerCase();
        const cls = origContent.className;
        let liveEl = null;
        if (origContent.id) {
          liveEl = document.getElementById(origContent.id);
        } else if (cls) {
          // Find by tag + exact class match
